// Gemini: 深度解析详情页，通过 window._gallery 提取高清原图
const card = async (link = '') => {
  const { parseHTML } = await import('linkedom')
  const document = await fetch(link)
    .then(r => r.text())
    .then(parseHTML)
    .then(v => v.document)

  // 基础标题提取
  const title = document.querySelector('h1.title')?.innerText.trim()
  const subtitle = document.querySelector('h2.title')?.innerText.trim()

  // 标签提取与格式化
  // Gemini: 保持与 venera 一样的标签识别逻辑，并支持点击跳转搜索
  const word = []
  // if (title) word.push(title)
  // if (subtitle) word.push(subtitle)

  const tags = [...document.querySelectorAll('.tag-container')].map(container => {
    const category = container.firstChild.textContent.trim().replace(':', '').toLowerCase()
    if (category === 'uploaded') {
      const timeEl = container.querySelector('time')
      if (timeEl) word.push(`上传: ${timeEl.innerText.trim()}`)
      return []
    }

    return [...container.querySelectorAll('.tag')].map(tag => {
      const tagName = tag.querySelector('.name')?.innerText.trim()
      // Gemini: 生成搜索指令，如 "Chinese@q=language:chinese"
      return `${tagName}@q=${category}:"${tagName}"`
    })
  }).flat().filter(Boolean)

  word.push(...tags)

  // 核心：解析 window._gallery 脚本
  let images = []
  const scripts = [...document.querySelectorAll('script')]
  const galleryScript = scripts.find(s => s.innerText.includes('window._gallery = JSON.parse('))?.innerText

  if (galleryScript) {
    try {
      // 提取 JSON.parse() 内部的字符串并还原
      const rawMatch = galleryScript.match(/JSON\.parse\("(.+)"\);/)?.[1]
      if (rawMatch) {
        // 还原转义字符 \u0022 -> ", \u005C -> \
        const decoded = JSON.parse(rawMatch.replace(/\\u0022/g, '"').replace(/\\u005C/g, '\\\\'))
        const mediaId = decoded.media_id
        images = decoded.images.pages.map((img, i) => {
          const ext = { p: 'png', j: 'jpg', g: 'gif', w: 'webp' }[img.t] || 'jpg'
          return `https://i3.nhentai.net/galleries/${mediaId}/${i + 1}.${ext}`
        })
      }
    } catch (e) {
      // 解析失败则尝试缩略图降级方式或记录错误
      console.log('Gemini: 解析 _gallery 脚本失败', e)
    }
  }

  return {
    word: word,
    card: [{ image: images }]
  }
}

